import { useState } from 'react';
import { View, Image, TouchableOpacity, Alert, ActivityIndicator } from 'react-native';
import * as ImagePicker from 'expo-image-picker';
import { useAuthStore } from '../stores/authStore';
import api from '../services/api';

export default function ProfileScreen() {
  const { user, updateUser } = useAuthStore();
  const [uploading, setUploading] = useState(false);
  const [localAvatar, setLocalAvatar] = useState(null);

  const pickImage = async () => {
    const { status } = await ImagePicker.requestMediaLibraryPermissionsAsync();
    if (status !== 'granted') {
      Alert.alert('Permission refusée', 'Nous avons besoin d\'accéder à vos photos.');
      return;
    }

    const result = await ImagePicker.launchImageLibraryAsync({
      mediaTypes: ImagePicker.MediaTypeOptions.Images,
      allowsEditing: true,
      aspect: [1, 1],
      quality: 0.7,
    });

    if (!result.canceled) {
      setLocalAvatar(result.assets[0].uri);
      uploadAvatar(result.assets[0]);
    }
  };

  const uploadAvatar = async (asset) => {
    setUploading(true);
    const formData = new FormData();
    formData.append('avatar', {
      uri: asset.uri,
      type: 'image/jpeg',
      name: 'avatar.jpg',
    });

    try {
      const response = await api.put('/user/avatar', formData, {
        headers: { 'Content-Type': 'multipart/form-data' },
      });
      updateUser({ ...user, avatarUrl: response.data.avatarUrl });
      Alert.alert('Succès', 'Photo de profil mise à jour');
    } catch (error) {
      Alert.alert('Erreur', 'Impossible de mettre à jour la photo');
    } finally {
      setUploading(false);
    }
  };

  return (
    <View>
      <TouchableOpacity onPress={pickImage} disabled={uploading}>
        {uploading ? (
          <ActivityIndicator />
        ) : (
          <Image
            source={{ uri: localAvatar || user?.avatarUrl || 'default_avatar_url' }}
            style={{ width: 100, height: 100, borderRadius: 50 }}
          />
        )}
        <View style={{ position: 'absolute', bottom: 0, right: 0, backgroundColor: 'blue', borderRadius: 20, padding: 5 }}>
          <Icon name="camera" size={20} color="white" />
        </View>
      </TouchableOpacity>
    </View>
  );
}
